import redis

def run_lua_script(redis_client, script_code, keys, args):
    """
    Executes a Lua script on the Redis server using redis.eval().

    Args:
        redis_client: An initialized Redis client instance.
        script_code: The Lua script code as a string.
        keys: A list of keys the script will access (passed as KEYS[] in Lua).
        args: A list of arguments for the script (passed as ARGV[] in Lua).

    Returns:
        The result of the Lua script execution.
    """
    return redis_client.eval(script_code, len(keys), *keys, *args)

